import{_ as a,o as i,c as s,a2 as o}from"./chunks/framework.DnrXFDHb.js";const e="/images/screenshots/cc-switch-codex-add-entry.png",c="/images/screenshots/cc-switch-github-assets-more.png",l="/images/screenshots/cc-switch-github-assets-installers.png",d="/images/screenshots/cc-switch-custom-provider.png",r="/images/screenshots/cc-switch-provider-form.png",h="/images/screenshots/cc-switch-enable-provider.png",n="/images/screenshots/cc-switch-codex-history-settings-entry.png",p="/images/screenshots/cc-switch-codex-history-general-scroll.png",C="/images/screenshots/cc-switch-codex-history-toggle.png",S=JSON.parse('{"title":"CC Switch 使用教程","description":"","frontmatter":{},"headers":[],"relativePath":"guide/config-switch.md","filePath":"guide/config-switch.md","lastUpdated":1782804092000}'),m={name:"guide/config-switch.md"};function g(b,t,w,u,x,k){return i(),s("div",null,[...t[0]||(t[0]=[o('<h1 id="cc-switch-使用教程" tabindex="-1">CC Switch 使用教程 <a class="header-anchor" href="#cc-switch-使用教程" aria-label="Permalink to &quot;CC Switch 使用教程&quot;">​</a></h1><p>CC Switch 是一个本机桌面配置管理工具。你可以用它保存 CCWS 的请求地址和 API Key，并在 Codex 等命令行工具之间切换配置。</p><p><img src="'+e+`" alt="CC Switch 配置界面" loading="lazy"></p><h2 id="适合什么时候用" tabindex="-1">适合什么时候用 <a class="header-anchor" href="#适合什么时候用" aria-label="Permalink to &quot;适合什么时候用&quot;">​</a></h2><ul><li>你同时有多个 API 服务或多个账号。</li><li>你不想每次手动修改 Codex 配置文件。</li><li>你需要在 CCWS 和其他配置之间快速切换。</li></ul><h2 id="安装-cc-switch" tabindex="-1">安装 CC Switch <a class="header-anchor" href="#安装-cc-switch" aria-label="Permalink to &quot;安装 CC Switch&quot;">​</a></h2><p>macOS 用户可以通过 Homebrew 安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tap</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> farion1231/ccswitch</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cc-switch</span></span></code></pre></div><p>也可以从 <a href="https://github.com/farion1231/cc-switch/releases" target="_blank" rel="noreferrer">CC Switch Releases</a> 页面下载最新安装包。打开页面后，先往下滑到 <code>Assets</code> 区域；如果只看到部分文件，点击「Show all ... assets」展开完整下载列表。</p><p><img src="`+c+'" alt="展开 GitHub Releases 资源列表" loading="lazy"></p><p>展开后按自己的系统选择安装包：</p><table tabindex="0"><thead><tr><th>系统</th><th>推荐下载</th></tr></thead><tbody><tr><td>macOS</td><td>下载文件名以 <code>macOS.dmg</code> 结尾的安装包</td></tr><tr><td>Windows</td><td>下载文件名以 <code>Windows.msi</code> 结尾的安装包</td></tr></tbody></table><p><img src="'+l+'" alt="选择 CC Switch 安装包" loading="lazy"></p><div class="tip custom-block"><p class="custom-block-title">提示</p><p>截图中的版本号只是示例。CC Switch 会持续更新，下载时以 Releases 页面实际显示的最新版本为准，不需要指定某一个固定版本。</p></div><p>安装完成后打开 CC Switch。首次启动时，如果它提示导入已有配置，可以按页面提示导入；如果你是第一次配置 Codex，也可以直接新建配置。</p><h2 id="安装完成后配置-ccws" tabindex="-1">安装完成后配置 CCWS <a class="header-anchor" href="#安装完成后配置-ccws" aria-label="Permalink to &quot;安装完成后配置 CCWS&quot;">​</a></h2><h3 id="进入-codex-配置" tabindex="-1">进入 Codex 配置 <a class="header-anchor" href="#进入-codex-配置" aria-label="Permalink to &quot;进入 Codex 配置&quot;">​</a></h3><ol><li>打开 CC Switch。</li><li>点击顶部的 Codex 图标。</li><li>点击右上角的「+」按钮。</li></ol><p><img src="'+e+'" alt="进入 Codex 配置并添加供应商" loading="lazy"></p><h3 id="选择自定义配置" tabindex="-1">选择自定义配置 <a class="header-anchor" href="#选择自定义配置" aria-label="Permalink to &quot;选择自定义配置&quot;">​</a></h3><ol><li>在「添加新供应商」页面，确认当前选择的是「Codex 供应商」。</li><li>在预设供应商中点击「自定义配置」。</li><li>如果页面内容较多，可以向下滚动继续填写。</li></ol><p><img src="'+d+'" alt="选择 Codex 自定义配置" loading="lazy"></p><h3 id="填写-ccws-信息" tabindex="-1">填写 CCWS 信息 <a class="header-anchor" href="#填写-ccws-信息" aria-label="Permalink to &quot;填写 CCWS 信息&quot;">​</a></h3><p>按下面内容填写：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>供应商名称</td><td>建议填写 <code>CCWS</code>，方便后续识别</td></tr><tr><td>官网链接</td><td>填写 <code>https://www.ccws.pro</code></td></tr><tr><td>API Key</td><td>粘贴当前账号生成的有效 Key</td></tr><tr><td>API 请求地址</td><td>Codex 配置填写 <code>https://www.ccws.pro/v1</code></td></tr></tbody></table><p>填写完成后，点击右下角「添加」。</p><p><img src="'+r+'" alt="填写 CCWS 供应商信息" loading="lazy"></p><div class="tip custom-block"><p class="custom-block-title">提示</p><p>「完整 URL」开关保持默认关闭即可。除非工作人员特别说明，否则只需要填写兼容 OpenAI Response 格式的服务端点地址。</p></div><h3 id="启用配置并重启-codex" tabindex="-1">启用配置并重启 Codex <a class="header-anchor" href="#启用配置并重启-codex" aria-label="Permalink to &quot;启用配置并重启 Codex&quot;">​</a></h3><ol><li>回到 CC Switch 列表，找到刚添加的 <code>CCWS</code>。</li><li>点击「启用」。</li><li>关闭当前终端窗口，并重新打开终端。</li><li>重新启动 Codex 后，发起一次简单测试，确认请求能正常发出。</li></ol><p><img src="'+h+'" alt="启用 CCWS 配置" loading="lazy"></p><h2 id="切换-provider-后显示-codex-会话历史" tabindex="-1">切换 Provider 后显示 Codex 会话历史 <a class="header-anchor" href="#切换-provider-后显示-codex-会话历史" aria-label="Permalink to &quot;切换 Provider 后显示 Codex 会话历史&quot;">​</a></h2><p>如果你在 CCWS、官方 OpenAI 或其他 Provider 之间切换后，发现 Codex 原来的聊天记录没有出现在历史列表里，可以开启 CC Switch 的统一会话历史设置。</p><h3 id="进入设置" tabindex="-1">进入设置 <a class="header-anchor" href="#进入设置" aria-label="Permalink to &quot;进入设置&quot;">​</a></h3><p>在 CC Switch 主界面点击左上方的齿轮按钮，进入设置页面。</p><p><img src="'+n+'" alt="进入 CC Switch 设置" loading="lazy"></p><h3 id="找到-codex-应用增强" tabindex="-1">找到 Codex 应用增强 <a class="header-anchor" href="#找到-codex-应用增强" aria-label="Permalink to &quot;找到 Codex 应用增强&quot;">​</a></h3><p>在「通用」页面向下滑动，找到「Codex 应用增强」区域。</p><p><img src="'+p+'" alt="在通用设置中向下滑动" loading="lazy"></p><h3 id="打开统一-codex-会话历史" tabindex="-1">打开统一 Codex 会话历史 <a class="header-anchor" href="#打开统一-codex-会话历史" aria-label="Permalink to &quot;打开统一 Codex 会话历史&quot;">​</a></h3><p>开启「统一 Codex 会话历史」。开启后，官方与第三方 Provider 的会话会出现在同一个历史列表里，切换配置后更容易找回之前的聊天记录。</p><p><img src="'+C+'" alt="开启统一 Codex 会话历史" loading="lazy"></p><div class="tip custom-block"><p class="custom-block-title">提示</p><p>如果页面提示迁移现有官方会话，可以按提示确认，迁移前会自动备份。跨 Provider 继续旧会话时，对方服务可能无法识别旧会话中的部分加密内容；重要任务建议在当前 Provider 下新开会话。</p></div><h2 id="验证与排查" tabindex="-1">验证与排查 <a class="header-anchor" href="#验证与排查" aria-label="Permalink to &quot;验证与排查&quot;">​</a></h2><p>如果仍然请求失败，优先检查：</p><ul><li>Codex 使用的请求地址是否为 <code>https://www.ccws.pro/v1</code>。</li><li>API Key 是否复制完整。</li><li>模型名称是否在 CCWS 当前支持范围内。</li></ul><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ul><li>不要把配置文件提交到公开仓库。</li><li>多人协作时只共享配置字段，不共享真实 Key。</li><li>以后尽量通过 CC Switch 修改和切换配置，减少手动编辑配置文件造成的冲突。</li><li>切换配置后，重新打开终端再验证是否生效。</li></ul>',48)])])}const y=a(m,[["render",g]]);export{S as __pageData,y as default};
